export const themes = {
  dark: {
    /* -------- Surfaces (Deep & Inky) -------- */
    '--bg-main': '#050505',
    '--bg-secondary': '#0b0c10',
    '--surface-glass': 'rgba(15, 15, 20, 0.75)',
    '--surface-border': 'rgba(255, 255, 255, 0.08)',
    
    /* -------- Branding (High Glow Emerald) -------- */
    '--accent-primary': '#10b981',   // Vivid Emerald
    '--accent-secondary': '#059669', // Darker Emerald
    '--accent-glow': 'rgba(16, 185, 129, 0.25)',
    
    /* -------- Typography (High Contrast) -------- */
    '--text-primary': '#ffffff',
    '--text-secondary': 'rgba(255, 255, 255, 0.7)',
    '--text-muted': 'rgba(255, 255, 255, 0.4)',
    
    /* -------- Interactive -------- */
    '--input-bg': 'rgba(255, 255, 255, 0.03)',
    '--input-border': 'rgba(255, 255, 255, 0.12)',
    '--shadow-elevated': '0 20px 60px rgba(0, 0, 0, 0.8)',
  },

  light: {
    /* -------- Surfaces (Clean & Professional) -------- */
    '--bg-main': '#f8fafc',
    '--bg-secondary': '#f1f5f9',
    '--surface-glass': 'rgba(255, 255, 255, 0.9)',
    '--surface-border': 'rgba(16, 185, 129, 0.15)', // Tinted border for visibility
    
    /* -------- Branding (Deep Emerald for Readability) -------- */
    '--accent-primary': '#059669',   // Slightly deeper for white background
    '--accent-secondary': '#047857',
    '--accent-glow': 'rgba(5, 150, 105, 0.1)',
    
    /* -------- Typography (Slate-based Gray) -------- */
    '--text-primary': '#0f172a',
    '--text-secondary': '#475569',
    '--text-muted': '#94a3b8',
    
    /* -------- Interactive -------- */
    '--input-bg': '#ffffff',
    '--input-border': '#e2e8f0',
    '--shadow-elevated': '0 20px 40px rgba(16, 185, 129, 0.08)',
  }
};
